@page "/patients"
@using VetClinic.Data.Models
@using VetClinic.Services
@inject PatientService PatientService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer

<PageTitle>Patients</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Patients</h1>
    <button class="btn btn-primary" @onclick="ShowRegisterForm">
        <span class="bi bi-plus"></span> Register New Pet
    </button>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search by pet name or owner last name..."
           @bind="searchQuery" @bind:event="oninput" @bind:after="SearchAsync" />
</div>

@if (showRegisterForm)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>Register New Pet</strong>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => showRegisterForm = false">Cancel</button>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6>Owner Information</h6>
                    <div class="mb-2">
                        <label class="form-label">First Name</label>
                        <input class="form-control" @bind="newOwner.FirstName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Last Name</label>
                        <input class="form-control" @bind="newOwner.LastName" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Phone</label>
                        <input class="form-control" @bind="newOwner.Phone" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Email</label>
                        <input class="form-control" @bind="newOwner.Email" />
                    </div>
                </div>
                <div class="col-md-6">
                    <h6>Pet Information</h6>
                    <div class="mb-2">
                        <label class="form-label">Name</label>
                        <input class="form-control" @bind="newPet.Name" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Species</label>
                        <select class="form-select" @bind="newPet.Species">
                            <option value="">Select...</option>
                            <option>Dog</option>
                            <option>Cat</option>
                            <option>Bird</option>
                            <option>Rabbit</option>
                            <option>Reptile</option>
                            <option>Other</option>
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Breed</label>
                        <input class="form-control" @bind="newPet.Breed" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date of Birth</label>
                        <input type="date" class="form-control" @bind="newPet.DateOfBirth" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <input type="number" step="0.1" class="form-control" @bind="newPet.Weight" />
                    </div>
                </div>
            </div>
            <button class="btn btn-success mt-3" @onclick="RegisterPetAsync">Save</button>
        </div>
    </div>
}

@if (pets == null)
{
    <p>Loading...</p>
}
else if (!pets.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr>
                <th>Pet Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Actions</th>
            </tr>
