@page "/patients/{Id:int}"
@using VetClinic.Data.Models
@using VetClinic.Services
@inject PatientService PatientService
@inject NavigationManager Navigation
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer

<PageTitle>Patient Details</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>@pet.Name</h1>
        <a href="/patients" class="btn btn-outline-secondary">Back to List</a>
    </div>

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between">
                    <strong>Pet Information</strong>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => editingPet = !editingPet">
                        @(editingPet ? "Cancel" : "Edit")
                    </button>
                </div>
                <div class="card-body">
                    @if (editingPet)
                    {
                        <div class="mb-2">
                            <label class="form-label">Name</label>
                            <input class="form-control" @bind="pet.Name" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Species</label>
                            <input class="form-control" @bind="pet.Species" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Breed</label>
                            <input class="form-control" @bind="pet.Breed" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Date of Birth</label>
                            <input type="date" class="form-control" @bind="pet.DateOfBirth" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Weight (kg)</label>
                            <input type="number" step="0.1" class="form-control" @bind="pet.Weight" />
                        </div>
                        <button class="btn btn-success" @onclick="SavePetAsync">Save</button>
                    }
                    else
                    {
                        <dl class="row mb-0">
                            <dt class="col-sm-4">Species</dt><dd class="col-sm-8">@pet.Species</dd>
                            <dt class="col-sm-4">Breed</dt><dd class="col-sm-8">@pet.Breed</dd>
                            <dt class="col-sm-4">Date of Birth</dt><dd class="col-sm-8">@pet.DateOfBirth.ToShortDateString()</dd>
                            <dt class="col-sm-4">Weight</dt><dd class="col-sm-8">@pet.Weight kg</dd>
                            <dt class="col-sm-4">Owner</dt><dd class="col-sm-8">@pet.Owner.FullName</dd>
                        </dl>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header"><strong>Owner Information</strong></div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Name</dt><dd class="col-sm-8">@pet.Owner.FullName</dd>
                        <dt class="col-sm-4">Phone</dt><dd class="col-sm-8">@pet.Owner.Phone</dd>
                        <dt class="col-sm-4">Email</dt><dd class="col-sm-8">@pet.Owner.Email</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>Medical History</strong>
            <button class="btn btn-sm btn-success" @onclick="() => showAddNote = !showAddNote">
                @(showAddNote ? "Cancel" : "Add Treatment Note")
            </button>
        </div>
        <div class="card-body">
            @if (showAddNote)
            {
                <div class="border rounded p-3 mb-3 bg-light">
                    <h6>New Treatment Note</h6>
                    <div class="row g-2">
                        <div class="col-md-6">
                            <label class="form-label">Date</label>
                            <input type="date" class="form-control" @bind="newNote.Date" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Veterinarian</label>
                            <input class="form-control" @bind="newNote.VeterinarianName" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Diagnosis</label>
                            <input class="form-control" @bind="newNote.Diagnosis" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Treatment</label>
                            <input class="form-control" @bind="newNote.Treatment" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Medications</label>
                            <input class="form-control" @bind="newNote.Medications" />
                        </div>
                        <div class="col-12">
                            <label class="form-label">Notes</label>
                            <textarea class="form-control" rows="2" @bind="newNote.Notes"></textarea>
                        </div>
                    </div>
                    <button class="btn btn-success mt-2" @onclick="AddNoteAsync">Save Note</button>
                </div>
            }

            @if (!pet.TreatmentNotes.Any())
            {
                <p class="text-muted">No treatment history recorded.</p>
            }
            else
            {
                @foreach (var note in pet.TreatmentNotes)
                {
                    <div class="border-bottom pb-2 mb-2">
                        <div class="d-flex justify-content-between">
                            <strong>@note.Date.ToShortDateString() — @note.Diagnosis</strong>
                            <span class="text-muted">Dr. @note.VeterinarianName</span>
                        </div>
                        <div><strong>Treatment:</strong> @note.Treatment</div>
                        @if (!string.IsNullOrEmpty(note.Medications))
                        {
                            <div><strong>Medications:</strong> @note.Medications</div>
                        }
                        @if (!string.IsNullOrEmpty(note.Notes))
                        {
                            <div class="text-muted"><em>@note.Notes</em></div>
                        }
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool editingPet;
    private bool showAddNote;
    private TreatmentNote newNote = new() { Date = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientService.GetPetAsync(Id);
    }

    private async Task SavePetAsync()
    {
        if (pet == null) return;
        await PatientService.UpdatePetAsync(pet);
        editingPet = false;
    }

    private async Task AddNoteAsync()
    {
        if (pet == null) return;
        newNote.PetId = pet.Id;
        await PatientService.AddTreatmentNoteAsync(newNote);
        pet = await PatientService.GetPetAsync(Id);
        newNote = new TreatmentNote { Date = DateTime.Today };
        showAddNote = false;
    }
}
