@page "/appointments"
@using VetClinic.Data.Models
@using VetClinic.Services
@inject AppointmentService AppointmentService
@inject PatientService PatientService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer

<PageTitle>Appointments</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Appointments</h1>
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        <span class="bi bi-plus"></span> New Appointment
    </button>
</div>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointmentsAsync" />
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</strong>
            <button class="btn btn-sm btn-outline-secondary" @onclick="() => showForm = false">Cancel</button>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="editingAppointment.PetId">
                        <option value="0">Select patient...</option>
                        @if (allPets != null)
                        {
                            @foreach (var pet in allPets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        }
                    </select>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Start Time</label>
                    <input type="datetime-local" class="form-control" @bind="editingAppointment.StartTime" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Time</label>
                    <input type="datetime-local" class="form-control" @bind="editingAppointment.EndTime" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Veterinarian</label>
                    <input class="form-control" @bind="editingAppointment.VeterinarianName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editingAppointment.Reason" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Notes</label>
                    <input class="form-control" @bind="editingAppointment.Notes" />
                </div>
            </div>
            @if (!string.IsNullOrEmpty(formError))
            {
                <div class="alert alert-danger mt-2">@formError</div>
            }
            <button class="btn btn-success mt-3" @onclick="SaveAppointmentAsync">Save</button>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h4>

<div class="card">
    <div class="card-body p-0">
        <table class="table table-hover mb-0">
            <thead class="table-light">
                <tr>
                    <th>Time</th>
                    <th>Patient</th>
                    <th>Owner</th>
                    <th>Veterinarian</th>
                    <th>Reason</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @if (appointments == null)
                {
                    <tr><td colspan="7">Loading...</td></tr>
                }
                else if (!appointments.Any())
                {
                    <tr><td colspan="7" class="text-muted text-center py-3">No appointments for this date.</td></tr>
                }
                else
                {
                    @foreach (var apt in appointments)
                    {
                        <tr class="@(apt.Status == AppointmentStatus.Cancelled ? "table-secondary text-decoration-line-through" : "")">
                            <td>@apt.StartTime.ToString("HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Pet.Owner.FullName</td>
                            <td>@apt.VeterinarianName</td>
                            <td>@apt.Reason</td>
                            <td>
                                <span class="badge @GetStatusBadge(apt.Status)">@apt.Status</span>
                            </td>
                            <td>
                                @if (apt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditAppointment(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointmentAsync(apt.Id)">Cancel</button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>
</div>

<div class="mt-3">
    <h5>Availability</h5>
    <div class="d-flex flex-wrap gap-1">
        @foreach (var slot in GetTimeSlots())
        {
            var isBooked = IsSlotBooked(slot);
            <span class="badge @(isBooked ? "bg-danger" : "bg-success")">
                @slot.ToString("HH:mm")
            </span>
        }
    </div>
    <small class="text-muted"><span class="badge bg-success">Available</span> <span class="badge bg-danger">Booked</span></small>
</div>

@code {
    private List<Appointment>? appointments;
    private List<Pet>? allPets;
    private DateTime selectedDate = DateTime.Today;
    private bool showForm;
    private Appointment editingAppointment = new();
    private string? formError;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointmentsAsync();
        allPets = await PatientService.GetPetsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        var from = selectedDate.Date;
        var to = from.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsAsync(from, to);
    }

    private void ShowCreateForm()
    {
        editingAppointment = new Appointment
        {
            StartTime = selectedDate.Date.AddHours(9),
            EndTime = selectedDate.Date.AddHours(9).AddMinutes(30)
        };
        formError = null;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = new Appointment
        {
            Id = apt.Id,
            PetId = apt.PetId,
            StartTime = apt.StartTime,
            EndTime = apt.EndTime,
            Reason = apt.Reason,
            VeterinarianName = apt.VeterinarianName,
            Notes = apt.Notes,
            Status = apt.Status
        };
        formError = null;
        showForm = true;
    }

    private async Task SaveAppointmentAsync()
    {
        formError = null;
        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a patient.";
            return;
        }

        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime,
            editingAppointment.Id == 0 ? null : editingAppointment.Id);

        if (!available)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment.Id == 0)
            await AppointmentService.CreateAppointmentAsync(editingAppointment);
        else
            await AppointmentService.UpdateAppointmentAsync(editingAppointment);

        showForm = false;
        await LoadAppointmentsAsync();
    }

    private async Task CancelAppointmentAsync(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointmentsAsync();
    }

    private List<DateTime> GetTimeSlots()
    {
        var slots = new List<DateTime>();
        for (var hour = 8; hour < 18; hour++)
        {
            slots.Add(selectedDate.Date.AddHours(hour));
            slots.Add(selectedDate.Date.AddHours(hour).AddMinutes(30));
        }
        return slots;
    }

    private bool IsSlotBooked(DateTime slot)
    {
        if (appointments == null) return false;
        var slotEnd = slot.AddMinutes(30);
        return appointments.Any(a => a.Status != AppointmentStatus.Cancelled && a.StartTime < slotEnd && a.EndTime > slot);
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

