                    <button class="btn btn-sm btn-outline-primary" @onclick="() => editingPet = !editingPet">
                        @(editingPet ? "Cancel" : "Edit")
                    </button>
                </div>
                <div class="card-body">
                    @if (editingPet)
                    {
                        <div class="mb-2">
                            <label class="form-label">Name</label>
                            <input class="form-control" @bind="pet.Name" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Species</label>
                            <input class="form-control" @bind="pet.Species" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Breed</label>
                            <input class="form-control" @bind="pet.Breed" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Date of Birth</label>
                            <input type="date" class="form-control" @bind="pet.DateOfBirth" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Weight (kg)</label>
