@code {
    private int petCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment>? upcomingAppointments;

    protected override async Task OnInitializedAsync()
    {
        var pets = await PatientService.GetPetsAsync();
        petCount = pets.Count;

        var today = DateTime.Today;
        var todayApts = await AppointmentService.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todayApts.Count(a => a.Status == AppointmentStatus.Scheduled);
        upcomingAppointments = todayApts
            .Where(a => a.Status == AppointmentStatus.Scheduled && a.StartTime >= DateTime.Now)
            .ToList();

        var invoices = await BillingService.GetInvoicesAsync();
        pendingInvoices = invoices.Count(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);
    }
}

