```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext context)
{
    // Owners
    public async Task<List<Owner>> GetOwnersAsync() =>
        await context.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await context.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task<Owner> CreateOwnerAsync(Owner owner)
    {
        context.Owners.Add(owner);
        await context.SaveChangesAsync();
        return owner;
    }

    public async Task UpdateOwnerAsync(Owner owner)
    {
        context.Owners.Update(owner);
        await context.SaveChangesAsync();
    }

    // Pets
    public async Task<List<Pet>> GetPetsAsync() =>
        await context.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet?> GetPetAsync(int id) =>
        await context.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<Pet> CreatePetAsync(Pet pet)
    {
        context.Pets.Add(pet);
        await context.SaveChangesAsync();
        return pet;
    }

    public async Task UpdatePetAsync(Pet pet)
    {
        context.Pets.Update(pet);
        await context.SaveChangesAsync();
    }

    // Treatment Notes
    public async Task<TreatmentNote> AddTreatmentNoteAsync(TreatmentNote note)
    {
        context.TreatmentNotes.Add(note);
        await context.SaveChangesAsync();
        return note;
    }

    public async Task<List<Pet>> SearchPetsAsync(string query)
    {
        if (string.IsNullOrWhiteSpace(query)) return await GetPetsAsync();
        var lower = query.ToLower();
        return await context.Pets
            .Include(p => p.Owner)
            .Where(p => p.Name.ToLower().Contains(lower) || p.Owner.LastName.ToLower().Contains(lower))
            .OrderBy(p => p.Name)
            .ToListAsync();
    }
}
```

2. **AppointmentService.cs** - Service for managing appointments:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext context)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        var query = context.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue) query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue) query = query.Where(a => a.StartTime <= to.Value);
        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await context.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        context.Appointments.Add(appointment);
        await context.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        context.Appointments.Update(appointment);
        await context.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var apt = await context.Appointments.FindAsync(id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await context.SaveChangesAsync();
        }
    }

    public async Task<List<Appointment>> GetAvailabilityAsync(DateTime date)
    {
        var start = date.Date;
        var end = start.AddDays(1);
        return await context.Appointments
            .Where(a => a.StartTime >= start && a.StartTime < end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<bool> IsSlotAvailableAsync(DateTime startTime, DateTime endTime, int? excludeId = null)
    {
        var query = context.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime < endTime && a.EndTime > startTime);
        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);
        return !await query.AnyAsync();
    }
}
```

3. **BillingService.cs** - Service for billing and payments:
```csharp
using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext context)
{
    public async Task<List<Invoice>> GetInvoicesAsync() =>
        await context.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await context.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Appointment)
            .Include(i => i.Payments.OrderByDescending(p => p.PaymentDate))
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        context.Invoices.Add(invoice);
        await context.SaveChangesAsync();
        return invoice;
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        context.Payments.Add(payment);
        var invoice = await context.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == payment.InvoiceId);
        var totalPaid = invoice.Payments.Where(p => !p.IsRefund).Sum(p => p.Amount)
                      - invoice.Payments.Where(p => p.IsRefund).Sum(p => p.Amount)
                      + (payment.IsRefund ? -payment.Amount : payment.Amount);
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        else if (totalPaid > 0)
            invoice.Status = InvoiceStatus.PartiallyPaid;
        await context.SaveChangesAsync();
        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync() =>
        await context.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();
}
```

