@code {
    private List<Appointment>? appointments;
    private List<Pet>? allPets;
    private DateTime selectedDate = DateTime.Today;
    private bool showForm;
    private Appointment editingAppointment = new();
    private string? formError;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointmentsAsync();
        allPets = await PatientService.GetPetsAsync();
    }

    private async Task LoadAppointmentsAsync()
    {
        var from = selectedDate.Date;
        var to = from.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsAsync(from, to);
    }

    private void ShowCreateForm()
    {
        editingAppointment = new Appointment
        {
            StartTime = selectedDate.Date.AddHours(9),
            EndTime = selectedDate.Date.AddHours(9).AddMinutes(30)
        };
        formError = null;
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = new Appointment
        {
            Id = apt.Id,
            PetId = apt.PetId,
            StartTime = apt.StartTime,
            EndTime = apt.EndTime,
            Reason = apt.Reason,
            VeterinarianName = apt.VeterinarianName,
            Notes = apt.Notes,
            Status = apt.Status
        };
        formError = null;
        showForm = true;
    }

    private async Task SaveAppointmentAsync()
    {
        formError = null;
        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a patient.";
            return;
        }

        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime,
            editingAppointment.Id == 0 ? null : editingAppointment.Id);

        if (!available)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        if (editingAppointment.Id == 0)
            await AppointmentService.CreateAppointmentAsync(editingAppointment);
        else
            await AppointmentService.UpdateAppointmentAsync(editingAppointment);

        showForm = false;
        await LoadAppointmentsAsync();
    }

    private async Task CancelAppointmentAsync(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointmentsAsync();
    }

    private List<DateTime> GetTimeSlots()
    {
        var slots = new List<DateTime>();
        for (var hour = 8; hour < 18; hour++)
        {
            slots.Add(selectedDate.Date.AddHours(hour));
            slots.Add(selectedDate.Date.AddHours(hour).AddMinutes(30));
        }
        return slots;
    }

    private bool IsSlotBooked(DateTime slot)
    {
        if (appointments == null) return false;
        var slotEnd = slot.AddMinutes(30);
        return appointments.Any(a => a.Status != AppointmentStatus.Cancelled && a.StartTime < slotEnd && a.EndTime > slot);
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}
```

